### Core Classes and Functions

Let's start by implementing the core classes and functions.

#### 1. Board Class

```python
"""
This class represents the Checkers board.
"""

class Board:
    def __init__(self):
        self.grid = [[None for _ in range(8)] for _ in range(8)]
        self.setup_board()

    def setup_board(self):
        # Place pieces on the board
        for row in range(3, 5):
            for col in range((row + 1) % 2, 8, 2):
                self.grid[row][col] = Piece('r')
        for row in range(6, 8):
            for col in range((row + 1) % 2, 8, 2):
                self.grid[row][col] = Piece('b')

    def move_piece(self, from_pos, to_pos):
        # Move a piece from one position to another
        if (from_pos[0], from_pos[1]) in self.get_possible_moves():
            self.grid[to_pos[0]][to_pos[1]] = self.grid[from_pos[0]][from_pos[1]]
            self.grid[from_pos[0]][from_pos[1]] = None

    def get_possible_moves(self):
        # Return all possible moves for the current player
        possible_moves = []
        for row in range(8):
            for col in range(8):
                piece = self.grid[row][col]
                if piece and piece.color == 'r':
                    moves = self.get_moves_for_piece((row, col))
                    possible_moves.extend(moves)
        return possible_moves

    def get_moves_for_piece(self, position):
        # Return all possible moves for a single piece
        moves = []
        row, col = position
        if self.grid[row][col].color == 'r':
            directions = [(1, 1), (1, -1)]
            if self.grid[row][col].is_king:
                directions.extend([(-1, 1), (-1, -1)])
            for dr, dc in directions:
                new_row, new_col = row + dr, col + dc
                if 0 <= new_row < 8 and 0 <= new_col < 8 and self.grid[new_row][new_col] is None:
                    moves.append((position, (new_row, new_col)))
        return moves

    def __str__(self):
        # Return a string representation of the board
        board_str = ''
        for row in self.grid:
            for cell in row:
                if cell:
                    board_str += cell.symbol + ' '
                else:
                    board_str += '. '
            board_str += '\n'
        return board_str

class Piece:
    def __init__(self, color):
        self.color = color
        self.is_king = False
        self.symbol = 'R' if color == 'r' else 'B'

    def king(self):
        self.is_king = True
```

#### 2. Player Class

```python
"""
This class represents a player.
"""

class Player:
    def __init__(self, color):
        self.color = color
        self.name = "Player {}".format(color)

    def get_move(self, board):
        # Get a move from the user
        print(board)
        from_pos = input("Enter the position of the piece to move (e.g., 0 2): ").split()
        to_pos = input("Enter the target position (e.g., 1 3): ").split()
        return (int(from_pos[0]), int(from_pos[1])), (int(to_pos[0]), int(to_pos[1]))
```

#### 3. Game Class

```python
"""
This class manages the game state and rules.
"""

class Game:
    def __init__(self):
        self.board = Board()
        self.current_player = Player('r')

    def play(self):
        while True:
            from_pos, to_pos = self.current_player.get_move(self.board)
            if (from_pos, to_pos) in self.board.get_possible_moves():
                self.board.move_piece(from_pos, to_pos)
                if self.board.get_possible_moves() == []:
                    print("Game Over!")
                    if self.current_player.color == 'r':
                        print("Black wins!")
                    else:
                        print("Red wins!")
                    break
                self.current_player = Player('b' if self.current_player.color == 'r' else 'r')
            else:
                print("Invalid move. Please try again.")
```

#### 4. Main Module

```python
"""
This is the main module to launch the program.
"""

from game import Game

def run():
    game = Game()
    game.play()

if __name__ == "__main__":
    run()
```

